const e={"CA-1":{title:"Policy and Procedures",body:"[ORG] has developed, documented, and disseminated an Assessment, Authorization, and Monitoring Policy consistent with DoDI 8510.01, NIST SP 800-37 Rev 2, and CSRMC. Reviewed annually. The [ISSM] is responsible for the assessment and authorization program.",tools:[]},"CA-2":{title:"Control Assessments",body:"Annual assessments by qualified assessors coordinated by [ISSM] and approved by [AO]. Methods: documentation examination, interviews, control testing. [TOOL:scap] provides automated STIG assessment. [TOOL:acas] provides vulnerability assessment. [TOOL:splunk] supports audit log analysis. Results documented in SAR maintained in [TOOL:emass].",tools:["scap","acas","splunk","emass"]},"CA-2(1)":{title:"Control Assessments | Independent Assessors",body:"[SYSTEM] employs assessors or assessment teams with independence from the personnel responsible for operating the system. Independent assessors are selected by the [AO] in coordination with the [ISSM]. Assessors do not have operational responsibilities for [SYSTEM]. Independence criteria are documented and verified before assessment begins. Assessment independence is maintained throughout the assessment process.",tools:[]},"CA-2(2)":{title:"Control Assessments | Specialized Assessments",body:"[ORG] includes specialized assessment types as part of the security control assessment for [SYSTEM]. Specialized assessments include: penetration testing (annually), red team exercises (biannually for high-impact systems), and [TOOL:acas] automated scanning. Penetration testing targets [SYSTEM]-specific attack surfaces. Specialized assessment results are incorporated into the SAR and drive POAM entries in [TOOL:emass].",tools:["acas","emass"]},"CA-2(3)":{title:"Control Assessments | Leveraging Results from External Organizations",body:"[ORG] leverages assessment results performed by other organizations when those results meet [ORG]'s requirements. DoD RMF assessment results are leveraged per reciprocity principles where system boundaries overlap. [TOOL:crowdstrike], [TOOL:paloalto], and [TOOL:ivanti] FedRAMP/DoD PA assessment results are reviewed and leveraged where applicable. Leveraging decisions are documented and approved by the [AO].",tools:["crowdstrike","paloalto","ivanti"]},"CA-3":{title:"Information Exchange",body:"External connections controlled through ISAs and MOUs approved by the [AO]. [TOOL:paloalto] enforces technical controls. Documentation maintained in [TOOL:emass] and reviewed annually. [ISSO] monitors via [TOOL:splunk] and reports anomalies within 24 hours.",tools:["paloalto","emass","splunk"]},"CA-3(6)":{title:"Information Exchange | Transfer Policies and Agreements",body:"[SYSTEM] implements transfer policies consistent with applicable federal laws, executive orders, directives, regulations, policies, standards, and guidelines. Information transfer agreements are documented and approved by the [AO]. [TOOL:paloalto] DLP policies enforce transfer restrictions. CUI transfer complies with applicable CUI handling requirements. Transfer policies are reviewed annually.",tools:["paloalto"]},"CA-5":{title:"Plan of Action and Milestones",body:"POAM maintained in [TOOL:emass], updated monthly by [ISSO], reviewed quarterly by [ISSM], accepted by [AO] annually. CAT I: 30-day timelines; CAT II: 90-day; CAT III: 180-day. Sources include [TOOL:acas] scans, [TOOL:scap] results, and self-assessment findings.",tools:["emass","acas","scap"]},"CA-5(1)":{title:"Plan of Action and Milestones | Automation Support for Accuracy and Currency",body:"[SYSTEM] employs automated mechanisms to help ensure the POAM is accurate, up to date, and available. [TOOL:emass] provides automated POAM management. [TOOL:acas]/[TOOL:tenablesc] vulnerability scan data feeds directly into POAM entries. [TOOL:scap] compliance results automatically update POAM status. Automated data feeds ensure POAM currency without manual data entry. POAM accuracy is validated monthly by the [ISSO].",tools:["emass","acas","tenablesc","scap"]},"CA-6":{title:"Authorization",body:"[SYSTEM] has been granted an ATO by the designated [AO] per DoDI 8510.01. ATO package including SSP, SAR, and POAM maintained in [TOOL:emass]. [ISSO] monitors authorization status and initiates reauthorization 6 months before expiration. Significant changes assessed for authorization impact. Status reported to [AO] monthly.",tools:["emass"]},"CA-6(1)":{title:"Authorization | Joint Authorization — Intra-Organization",body:"[SYSTEM] implements joint authorization with other organizational systems as required. Joint authorization is coordinated through the [ISSM] and [AO]. Authorization packages for jointly authorized systems are maintained in [TOOL:emass]. Joint authorization agreements define responsibility boundaries. The [ISSO] coordinates assessment activities for jointly authorized system components.",tools:["emass"]},"CA-7":{title:"Continuous Monitoring",body:"Continuous monitoring per CSRMC Phase 5 and NIST SP 800-137. Elements: weekly [TOOL:acas]/[TOOL:tenablesc] scans; continuous [TOOL:crowdstrike] EDR; real-time [TOOL:splunk] SIEM; continuous [TOOL:hbss] AV/HIPS; quarterly [TOOL:scap] STIG compliance; monthly POAM review in [TOOL:emass]; annual control assessment. [ISSO] reviews weekly, reports to [ISSM] monthly, briefs [AO] quarterly. Supports cATO authorization objective.",tools:["acas","tenablesc","crowdstrike","splunk","hbss","scap","emass"]},"CA-7(1)":{title:"Continuous Monitoring | Independent Assessment",body:"[ORG] employs assessors with independence to monitor security controls on an ongoing basis. Independent security monitoring is conducted by personnel without operational responsibility for [SYSTEM]. [TOOL:crowdstrike] and [TOOL:splunk] provide automated independent monitoring. Independent assessment findings are reported directly to the [ISSM] and [AO]. Independence requirements are verified before continuous monitoring personnel are assigned.",tools:["crowdstrike","splunk"]},"CA-7(3)":{title:"Continuous Monitoring | Trend Analyses",body:"[ORG] employs trend analyses to determine if security control implementations, frequencies of continuous monitoring activities, and types of changes to systems are in alignment with organizational risk tolerance. [TOOL:splunk] provides trending dashboards tracking: POAM closure rates, vulnerability counts by severity, STIG compliance percentages, and incident frequency. [TOOL:acas]/[TOOL:tenablesc] trend reports show vulnerability posture over time. Trend analysis results are reviewed by the [ISSO] monthly and [ISSM] quarterly.",tools:["splunk","acas","tenablesc"]},"CA-7(4)":{title:"Continuous Monitoring | Risk Monitoring",body:"[ORG] ensures risk monitoring is an integral part of the continuous monitoring strategy. Risk monitoring includes: [TOOL:acas] vulnerability data, [TOOL:crowdstrike] threat intelligence, [TOOL:splunk] security event trends, and POAM aging analysis from [TOOL:emass]. Risk posture changes exceeding defined thresholds trigger notification to the [ISSM] and [AO]. Risk monitoring results are included in monthly ISSO reports.",tools:["acas","crowdstrike","splunk","emass"]},"CA-8":{title:"Penetration Testing",body:"Annual penetration testing by qualified testers under [ISSO] and [AO] authorization. Scope, rules of engagement, and methodology documented before testing. [TOOL:acas] identifies vulnerabilities supporting test planning. Results in penetration test report to [ISSO] and [ISSM]. Findings tracked in POAM in [TOOL:emass].",tools:["acas","emass"]},"CA-8(1)":{title:"Penetration Testing | Independent Penetration Testing Agent",body:"[SYSTEM] employs an independent penetration testing agent to perform penetration testing. Independent testers are selected by the [AO] and have no operational responsibility for [SYSTEM]. Tester independence is verified before engagement. Independent penetration test results are more credible and identify issues that internal assessors might overlook. Results are provided directly to the [ISSO], [ISSM], and [AO].",tools:[]},"CA-9":{title:"Internal System Connections",body:"Internal connections authorized and documented by [ISSO]. [TOOL:paloalto] enforces internal segmentation. [TOOL:cisco9300] implements VLAN segmentation. Documentation reviewed annually. Unauthorized connections detected by [TOOL:crowdstrike] and [TOOL:splunk] trigger immediate investigation.",tools:["paloalto","cisco9300","crowdstrike","splunk"]},"CA-9(1)":{title:"Internal System Connections | Compliance Checks",body:"[SYSTEM] performs security compliance checks on internal system connections on an ongoing basis. [TOOL:acas]/[TOOL:tenablesc] scans validate compliance of internal connections. [TOOL:crowdstrike] verifies device health for all internally connected endpoints. [TOOL:scap] compliance checks are performed on newly connected systems before they join the production environment. Compliance check results are reviewed by the [ISSO] weekly.",tools:["acas","tenablesc","crowdstrike","scap"]}};export{e as default};
